import React, { useEffect, useState } from "react";
import { useDispatch, useSelector } from "react-redux";
import { getAllBlogs } from "../features/ads/adsSlice";
import { useNavigate } from "react-router-dom";

const POPUP_STYLES = `
  @keyframes pop-backdrop { from { opacity:0; } to { opacity:1; } }
  @keyframes pop-card { from { opacity:0; transform:scale(0.88) translateY(20px); } to { opacity:1; transform:scale(1) translateY(0); } }
  .ph-popup-backdrop { animation: pop-backdrop 0.3s ease forwards; }
  .ph-popup-card { animation: pop-card 0.45s cubic-bezier(0.34,1.56,0.64,1) forwards; }
  .ph-popup-close {
    position: absolute; top: 12px; right: 12px; z-index: 10;
    width: 32px; height: 32px; border-radius: 50%;
    background: rgba(0,0,0,0.55); border: none;q  
    color: #fff; font-size: 16px; display: flex; align-items: center; justify-content: center;
    cursor: pointer; transition: background 0.2s, transform 0.2s;
    font-family: sans-serif; line-height: 1;
  }
  .ph-popup-close:hover { background: #ef4444; transform: scale(1.1); }
  .ph-popup-btn {
    width: 100%; padding: 15px;
    background: linear-gradient(135deg, #0d9488, #14b8a6);
    color: #fff; border: none; border-radius: 18px;
    font-size: 13px; font-weight: 900; letter-spacing: 0.12em;
    text-transform: uppercase; cursor: pointer;
    box-shadow: 0 12px 28px rgba(13,148,136,0.35);
    transition: all 0.25s;
  }
  .ph-popup-btn:hover { transform: translateY(-2px); box-shadow: 0 16px 36px rgba(13,148,136,0.45); }
  .ph-popup-skip {
    display: block; text-align: center; margin-top: 12px;
    font-size: 11px; color: #94a3b8; cursor: pointer;
    font-weight: 600; letter-spacing: 0.05em;
    background: none; border: none; width: 100%;
  }
  .ph-popup-skip:hover { color: #64748b; }
`;

const Pop = () => {
  const dispatch = useDispatch();
  const navigate = useNavigate();
  const { blog: adData, isLoading, isFetched } = useSelector((state) => state.blog);
  const [showPopup, setShowPopup] = useState(false);
  const [adIndex, setAdIndex] = useState(0);

  // Data is now fetched in App.js

  const matchesPopup = (cat) => {
    if (!cat) return false;
    const c = cat.toLowerCase().trim();
    return c === 'popup' || c === 'pop up' || c === 'pop-up' || c === 'banner' || c === 'ad' || c === 'promo';
  };
  const popupAds = (adData || []).filter((item) => item.isPopup === true || matchesPopup(item.category));

  useEffect(() => {
    if (popupAds.length > 0) {
      const timer = setTimeout(() => {
        const randomIndex = Math.floor(Math.random() * popupAds.length);
        setAdIndex(randomIndex);
        setShowPopup(true);
      }, 1500); // show after 1.5s
      return () => clearTimeout(timer);
    }
  }, [popupAds.length]);



  const handleClose = () => setShowPopup(false);

  const handleAdClick = (subcategory) => {
    setShowPopup(false);
    if (subcategory) {
      const targetPath = subcategory.startsWith("/") ? subcategory : `/shop/${subcategory}`;
      navigate(targetPath);
    }
  };

  if (!showPopup || popupAds.length === 0) return null;
  const currentAd = popupAds[adIndex];
  if (!currentAd) return null;

  return (
    <>
      <style>{POPUP_STYLES}</style>
      <div
        className="ph-popup-backdrop"
        style={{
          position: "fixed", inset: 0, zIndex: 99999,
          display: "flex", alignItems: "center", justifyContent: "center",
          padding: "16px",
          background: "rgba(15,23,42,0.75)",
          backdropFilter: "blur(6px)",
        }}
        onClick={handleClose}
      >
        {/* Card */}
        <div
          className="ph-popup-card"
          style={{
            position: "relative", width: "100%", maxWidth: "480px",
            background: "#fff", borderRadius: "28px",
            overflow: "hidden",
            boxShadow: "0 40px 80px rgba(0,0,0,0.35)",
          }}
          onClick={(e) => e.stopPropagation()}
        >
          {/* Close Button */}
          <button className="ph-popup-close" onClick={handleClose} aria-label="Close">✕</button>

          {/* Image */}
          <div
            style={{ position: "relative", height: "260px", overflow: "hidden", cursor: "pointer" }}
            onClick={() => handleAdClick(currentAd.subcategory)}
          >
            {currentAd.images?.[0]?.secure_url ? (
              <img
                src={
                  currentAd?.images?.[0]?.secure_url ||
                  "https://res.cloudinary.com/dpkv77m87/image/upload/v1711200000/fallback_product_image.png"
                }
                alt={currentAd.title}
                style={{ width: "100%", height: "100%", objectFit: "cover", transition: "transform 0.6s" }}
                onMouseOver={e => e.currentTarget.style.transform = "scale(1.06)"}
                onMouseOut={e => e.currentTarget.style.transform = "scale(1)"}
              />
            ) : (
              <div style={{ width: "100%", height: "100%", background: "linear-gradient(135deg,#0d9488,#14b8a6)", display: "flex", alignItems: "center", justifyContent: "center", fontSize: "64px" }}>
                💊
              </div>
            )}
            {/* Overlay gradient */}
            <div style={{ position: "absolute", inset: 0, background: "linear-gradient(to top, rgba(0,0,0,0.62) 0%, transparent 55%)" }} />
            {/* Badge */}
            <div style={{
              position: "absolute", bottom: "16px", left: "16px",
              background: "#facc15", color: "#1a1a1a",
              fontSize: "10px", fontWeight: "900", textTransform: "uppercase",
              letterSpacing: "0.15em", padding: "5px 12px", borderRadius: "100px",
            }}>
              ⚡ Limited Offer
            </div>
          </div>

          {/* Body */}
          <div style={{ padding: "24px 28px 28px" }}>
            {/* Pill */}
            <div style={{
              display: "inline-block",
              fontSize: "10px", fontWeight: "900", color: "#0d9488",
              background: "#f0fdfa", border: "1px solid #ccfbf1",
              padding: "4px 12px", borderRadius: "100px",
              letterSpacing: "0.15em", textTransform: "uppercase",
              marginBottom: "10px",
            }}>
              Pulse Addis
              {currentAd.title}
            </div>

            <div
              style={{
                fontSize: "13px", color: "#64748b", lineHeight: "1.6",
                marginBottom: "20px",
                display: "-webkit-box", WebkitLineClamp: 2,
                WebkitBoxOrient: "vertical", overflow: "hidden",
                fontFamily: "'Inter',sans-serif",
              }}
              dangerouslySetInnerHTML={{ __html: currentAd.description }}
            />

            <button className="ph-popup-btn" onClick={() => handleAdClick(currentAd.subcategory)}>
              Shop This Offer →
            </button>
            <button className="ph-popup-skip" onClick={handleClose}>
              No thanks, continue browsing
            </button>



          </div>
        </div>
      </div>
    </>
  );
};

export default Pop;
